WHERE source_chat_id = #{sourceChatId}
  AND message_id = #{messageId}
  AND target_chat_id = #{targetChatId}

mapper.insert:
INSERT INTO forward_task (
    source_chat_id, message_id, target_chat_id, status
    , source_chat_title
    , target_chat_title
